 {"id":"franken_networkx-3mxf","title":"Restore rooted_product parity for mixed directedness","description":"networkx.rooted_product accepts mixed Graph/DiGraph inputs and still returns an undirected Graph. FrankenNetworkX still routes through _validate_product_graph_types and raises NetworkXError when G and H differ in directedness. Remove that restriction for rooted_product and add parity coverage for both mixed-direction combinations.","status":"closed","priority":1,"issue_type":"bug","created_at":"2026-04-18T18:35:58.376548408Z","created_by":"ubuntu","updated_at":"2026-04-18T18:37:58.438005845Z","closed_at":"2026-04-18T18:37:58.436121818Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0}
